dir.commands:



select 'set$Form$DefaultValue(this);' as message
return



    &XMLWhenFilterLoading;
    &XMLWhenFilterClosing;



select '' as field, '' as message, 'remove$GridReport$Filter(this.grid);' as script
return

script.text:
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {sender.add_onResponseComplete(on$Filter$ResponseComplete);}
function set$Form$DefaultValue(f) {
  var g = f.grid, v = g._discountType ? g._discountType : '';
  f.setItemControlBehavior('loai_ck', g._discountKind, g._discountKindName, true);
  f.setItemValue('kieu_ck', v);
  setValue$Filter$Discount(f, v);
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function onChange$Filter$Discount(o) {o.parentForm.request('Discount', 'Discount', ['ma_ck'], o);}
function addExternalDiscountKey(f, k, c) {
  if (f.getItem(c).disabled) return;
  var v = $func.trim(f.getItemValue(c));
  if (v != '') Array.add(k, {Name: c, Opr: 'like', Value: v += '%', Type: 'String', Ignore: false});
}
function setObject$Filter$Discount(f, c, t, v) {
  var a = c.split(','), b = (t.indexOf(v) > -1);
  if (t == '') b = true;
  for (var i = 0; i < a.length; i++) {
    o = f.getItem($func.trim(a[i]));
    o.disabled = !b;
    f._setReadOnly(o, !b);
    if (b) {if (!f._objectFocus) f._objectFocus = o;}
      else o.value = '';
  }
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = new Array(), ref = $func.trim(f.getItem('ten_ck%l').value);
      g._discountCode = f.getItemValue('ma_ck');
      g._discountType = f.getItemValue('kieu_ck');
      g._discountKind = f.getItemValue('loai_ck');
      g._discountKindName = f.getItemValue('ten_loai_ck%l');
      Array.add(k, {Name: 'ma_ck', Opr: '=', Value: g._discountCode, Type: 'String', Ignore: false});
      Array.add(k, {Name: 'ngay_hl', Opr: '>=', Value: f.getItemValue('ngay_hl'), Type: 'DateTime', Ignore: false});
      addExternalDiscountKey(f, k, 'ma_kho');
      addExternalDiscountKey(f, k, 'ma_kh');
      addExternalDiscountKey(f, k, 'nh_kh1');
      addExternalDiscountKey(f, k, 'nh_kh2');
      addExternalDiscountKey(f, k, 'nh_kh3');
      addExternalDiscountKey(f, k, 'nh_kh9');
      addExternalDiscountKey(f, k, 'ma_vt');
      addExternalDiscountKey(f, k, 'nh_vt1');
      addExternalDiscountKey(f, k, 'nh_vt2');
      addExternalDiscountKey(f, k, 'nh_vt3');
      addExternalDiscountKey(f, k, 'nh_vt9');
      g.set_externalKey(k);
      g._alterTitle = [null, [['%s1', $func.trim(g._discountCode), true], ['%s2', ref, true]]];

      var a = g._discountType.split(',');
      if (a.length == 0) break;
      var t = a[0], r = a[1];
      g._hiddenFields = [
        {Fields: 'ma_kho', Value: !(t.indexOf('S') > -1)},
        {Fields: 'ma_kh, ten_kh%l', Value: !(t.indexOf('C') > -1)},
        {Fields: 'nh_kh1, ten_nh_kh1%l', Value: !(t.indexOf('D') > -1)},
        {Fields: 'nh_kh2, ten_nh_kh2%l', Value: !(t.indexOf('E') > -1)},
        {Fields: 'nh_kh3, ten_nh_kh3%l', Value: !(t.indexOf('F') > -1)},
        {Fields: 'nh_kh9, ten_nh_kh9%l', Value: !(t.indexOf('G') > -1)},
        {Fields: 'ma_vt, ten_vt%l, dvt, so_luong', Value: !(t.indexOf('I') > -1)},
        {Fields: 'nh_vt1, ten_nh_vt1%l', Value: !(t.indexOf('X') > -1)},
        {Fields: 'nh_vt2, ten_nh_vt2%l', Value: !(t.indexOf('Y') > -1)},
        {Fields: 'nh_vt3, ten_nh_vt3%l', Value: !(t.indexOf('Z') > -1)},
        {Fields: 'nh_vt9, ten_nh_vt9%l', Value: !(t.indexOf('T') > -1)},
        {Fields: 'tl_ck', Value: !(r.indexOf('0') > -1)},
        {Fields: 'tien_ck, ma_nt', Value: !(r.indexOf('1') > -1)}
      ];
      remove$GridReport$Filter(g);
      break;
    case 'Discount':
      f.setItemControlBehavior('loai_ck', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('kieu_ck', result[2].Value, null, true);
      var t = result[2].Value.split(',')[0];
      f._objectFocus = null;
      setValue$Filter$Discount(f, t);
      if (f._objectFocus) f._objectFocus.focus();
      break;
    default:
      break;
  }
}
function setValue$Filter$Discount(f, t) {
  setObject$Filter$Discount(f, 'ma_kho, ten_kho%l', t, 'S');
  setObject$Filter$Discount(f, 'ma_kh, ten_kh%l', t, 'C');
  setObject$Filter$Discount(f, 'nh_kh1, ten_nh_kh1%l', t, 'D');
  setObject$Filter$Discount(f, 'nh_kh2, ten_nh_kh2%l', t, 'E');
  setObject$Filter$Discount(f, 'nh_kh3, ten_nh_kh3%l', t, 'F');
  setObject$Filter$Discount(f, 'nh_kh9, ten_nh_kh9%l', t, 'G');
  setObject$Filter$Discount(f, 'ma_vt, ten_vt%l', t, 'I');
  setObject$Filter$Discount(f, 'nh_vt1, ten_nh_vt1%l', t, 'X');
  setObject$Filter$Discount(f, 'nh_vt2, ten_nh_vt2%l', t, 'Y');
  setObject$Filter$Discount(f, 'nh_vt3, ten_nh_vt3%l', t, 'Z');
  setObject$Filter$Discount(f, 'nh_vt9, ten_nh_vt9%l', t, 'T');
}
/* </flatten> */
